// src/app/layout.tsx
"use client";

import { useState } from "react";
import { usePathname } from "next/navigation";
import Link from "next/link";
import { 
  Home, Lock, MessageSquare, Gamepad2, Settings, 
  ChevronLeft, ChevronRight, LogOut 
} from "lucide-react";
import "./globals.css";

export default function RootLayout({ children }: { children: React.ReactNode }) {
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false);
  const pathname = usePathname();

  return (
    <html lang="pt-BR">
      <body>
        {/* ENVOLTÓRIO PRINCIPAL (Modelado do Verona) */}
        <div className="app-master-wrapper">
          
          {/* LUZES AMBIENTES (Orbs) */}
          <div className="ambient-orb orb-1"></div>
          <div className="ambient-orb orb-2"></div>

          {/* SIDEBAR DESKTOP */}
          <aside className={`desktop-sidebar ${sidebarCollapsed ? 'collapsed' : ''}`}>
            
            {/* BRAND AREA */}
            <div style={{ display: 'flex', alignItems: 'center', gap: '15px', marginBottom: '50px', justifyContent: sidebarCollapsed ? 'center' : 'flex-start' }}>
              <div style={{ width: '45px', height: '45px', flexShrink: 0, filter: 'drop-shadow(0 0 10px rgba(173,111,64,0.3))' }}>
                <img src="/images/Símbolo Rosa.png" alt="Atelier" style={{ width: '100%', height: '100%', objectFit: 'contain' }} />
              </div>
              {!sidebarCollapsed && (
                <div style={{ display: 'flex', flexDirection: 'column' }}>
                  <span className="font-elegant" style={{ fontSize: '26px', color: 'var(--atelier-creme)', lineHeight: '1' }}>Atelier</span>
                  <span style={{ fontSize: '10px', color: 'var(--atelier-terracota)', letterSpacing: '2px', textTransform: 'uppercase', fontWeight: 'bold' }}>Portal V2</span>
                </div>
              )}
            </div>

            {/* BOTÃO DE COLAPSO FLUTUANTE */}
            <button 
              onClick={() => setSidebarCollapsed(!sidebarCollapsed)}
              style={{ position: 'absolute', right: '-15px', top: '55px', background: 'var(--bg-app)', border: '1px solid var(--accent-color)', color: 'var(--accent-color)', borderRadius: '50%', width: '30px', height: '30px', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer', zIndex: 10 }}
            >
              {sidebarCollapsed ? <ChevronRight size={16} /> : <ChevronLeft size={16} />}
            </button>

            {/* MENU DE NAVEGAÇÃO */}
            <div style={{ flex: 1, overflowY: 'auto' }} className="hide-scrollbar">
              {!sidebarCollapsed && <div style={{ fontSize: '11px', textTransform: 'uppercase', fontWeight: 'bold', color: 'rgba(251,244,228,0.3)', letterSpacing: '1px', marginBottom: '15px', paddingLeft: '10px' }}>Visão Geral</div>}
              
              <Link href="/" className={`nav-item ${pathname === '/' ? 'active' : ''}`}>
                <Home size={20} strokeWidth={1.5} />
                {!sidebarCollapsed && <span>Home</span>}
              </Link>
              <Link href="/cofre" className={`nav-item ${pathname === '/cofre' ? 'active' : ''}`}>
                <Lock size={20} strokeWidth={1.5} />
                {!sidebarCollapsed && <span>O Cofre</span>}
              </Link>
              <Link href="/canais" className={`nav-item ${pathname === '/canais' ? 'active' : ''}`}>
                <MessageSquare size={20} strokeWidth={1.5} />
                {!sidebarCollapsed && <span>Canais</span>}
              </Link>
              <Link href="/gamificacao" className={`nav-item ${pathname === '/gamificacao' ? 'active' : ''}`}>
                <Gamepad2 size={20} strokeWidth={1.5} />
                {!sidebarCollapsed && <span>Conquistas</span>}
              </Link>
            </div>

            {/* CONFIGURAÇÕES E LOGOUT */}
            <div style={{ marginTop: 'auto', paddingTop: '20px', borderTop: '1px solid var(--border-soft)' }}>
              <Link href="/configuracoes" className={`nav-item ${pathname === '/configuracoes' ? 'active' : ''}`}>
                <Settings size={20} strokeWidth={1.5} />
                {!sidebarCollapsed && <span>Ajustes</span>}
              </Link>
              <div className="nav-item cursor-pointer" style={{ color: '#EF4444' }}>
                <LogOut size={20} strokeWidth={1.5} />
                {!sidebarCollapsed && <span>Sair</span>}
              </div>
            </div>

          </aside>

          {/* PALCO PRINCIPAL (Onde o Page.tsx vai carregar) */}
          <main className="main-stage">
            <div className="scroll-area hide-scrollbar">
              {children}
            </div>
          </main>

        </div>
      </body>
    </html>
  );
}